  }
  std::sort(a + 1, a + n + 1);
  n = std::unique(a + 1, a + n + 1) - a - 1;
  for (int i = 1, j = 0; i <= n; ++i) {
    for (; j < i && a[i] - a[j + 1] > k; ++j)
