### 第 7 题（2022 真题·阅读程序）该算法最准确的时间复杂度分析结果为 O(log n + k)。

```cpp
#include <iostream>
using namespace std;

int n, k;

int solve1() {
    int l = 0, r = n;
    while (l <= r) {
        int mid = (l + r) / 2;
        if (mid * mid <= n) l = mid + 1;
        else r = mid - 1;
    }
    return l - 1;
}

double solve2(double x) {
    if (x == 0) return x;
    for (int i = 0; i < k; i++)
        x = (x + n / x) / 2;
    return x;
}

int main() {
    cin >> n >> k;
    double ans = solve2(solve1());
    cout << ans << ' ' << (ans * ans == n) << endl;
    return 0;
}
```

**答案：A**

**解析：** solve1 二分查找 O(log n)，solve2 迭代 k 次 O(k)，总复杂度 O(log n + k)。

