队列存 (时间, 国籍)。每艘船到达时，把 24 小时前的弹出，统计不同国籍数。

```cpp
#include <bits/stdc++.h>
using namespace std;
int n,t,k,x,cnt[100005],ans;
queue<pair<int,int>> q;
int main() {
    cin>>n;
    while(n--) {
        cin>>t>>k;
        while(k--) {
            cin>>x;
            q.push({t,x});
            if(!cnt[x]) ans++;
            cnt[x]++;
        }
        while(!q.empty()&&t-q.front().first>=86400) {
            int c=q.front().second; q.pop();
            cnt[c]--;
            if(!cnt[c]) ans--;
        }
        cout<<ans<<"\n";
    }
    return 0;
}
```

判别式 Δ = b² − 4ac，Δ < 0 则输出 NO；Δ = 0 则输出 −b/2a 约分；Δ > 0 且 √Δ 为整数时输出 (−b+√Δ)/(2a) 约分。注意分母化为正。

```cpp
#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
ll gcd(ll a,ll b){return b?gcd(b,a%b):abs(a);}
int main() {
    int T;cin>>T;
    while(T--) {
        ll a,b,c;cin>>a>>b>>c;
        ll d=b*b-4*a*c;
        if(d<0){cout<<"NO\n";continue;}
        ll sq=sqrt(d);
        if(sq*sq!=d){cout<<"NO\n";continue;}
        ll p=-b+sq,q=2*a;
        if(q<0)p=-p,q=-q;
        ll g=gcd(p,q);
        p/=g;q/=g;
        if(q==1)cout<<p<<"\n";
        else cout<<p<<"/"<<q<<"\n";
    }
    return 0;
}
```
